#!/bin/sh
# Auto-generated Linux build script: portable 8bit build plus a
# no-assembly 8bit build, for comparison/testing (mirrors the intent of
# build/MSYS_jpsdr/GCC_Generic.sh).
set -e

mkdir -p 8bit_gcc_generic 8bit_gcc_generic_noasm

cd 8bit_gcc_generic
cmake ../../../source -DCMAKE_BUILD_TYPE=Release -DENABLE_LIBVMAF=ON -DENABLE_SCC_EXT=ON -DENABLE_MULTIVIEW=ON -DENABLE_ALPHA=ON -DENABLE_VAPOURSYNTH=ON -DENABLE_AVISYNTH=ON -DHIGH_BIT_DEPTH=OFF -DENABLE_HDR10_PLUS=OFF -DEXPORT_C_API=ON -DENABLE_SHARED=OFF -DENABLE_CLI=ON -DMAIN12=OFF -DENABLE_LTO=ON
make ${MAKEFLAGS}

cd ../8bit_gcc_generic_noasm
cmake ../../../source -DCMAKE_BUILD_TYPE=Release -DENABLE_LIBVMAF=ON -DENABLE_SCC_EXT=ON -DENABLE_MULTIVIEW=ON -DENABLE_ALPHA=ON -DENABLE_VAPOURSYNTH=ON -DENABLE_AVISYNTH=ON -DENABLE_ASSEMBLY=OFF -DHIGH_BIT_DEPTH=OFF -DENABLE_HDR10_PLUS=OFF -DEXPORT_C_API=ON -DENABLE_SHARED=OFF -DENABLE_CLI=ON -DMAIN12=OFF -DENABLE_LTO=ON
make ${MAKEFLAGS}
